    const V = new Set(nums);

    let totalMinSum = 0;

    // Step 2 & 3: For each x in nums, find d_x = min {d in V | d divides x}.
    for (const x of nums) {
        // Initialize d_min to x. This handles the case where x itself is the smallest divisor in V (or the only one).
        let d_min = x;

        // Find all divisors of x. Time complexity O(sqrt(x)).
        const limit = Math.floor(Math.sqrt(x));

        for (let i = 1; i <= limit; i++) {
            if (x % i === 0) {
                // i is a divisor
                const d1 = i;
                if (V.has(d1) && d1 < d_min) {
                    d_min = d1;
